class APIClient {
    private static final String BASE_URL_DEV = "https://api-dev.example.com/";
    private static final String BASE_URL_STAGING = "https://api-staging.example.com/";
    private static final String BASE_URL_PRODUCTION = "https://api.example.com/";
    
    private static Retrofit retrofit = null;

    public static Retrofit getClient(Environment env) {
        if (retrofit == null) {
            String baseUrl;
            switch (env) {
                case DEVELOPMENT:
                    baseUrl = BASE_URL_DEV;
                    break;
                case STAGING:
                    baseUrl = BASE_URL_STAGING;
                    break;
                case PRODUCTION:
                default:
                    baseUrl = BASE_URL_PRODUCTION;
                    break;
            }
            OkHttpClient client = new OkHttpClient.Builder().build();
            retrofit = new Retrofit.Builder()
                .baseUrl(baseUrl)
                .client(client)
                .addConverterFactory(GsonConverterFactory.create())
                .build();
        }
        return retrofit;
    }
}

